mapper.select:
SELECT *
FROM rag_outbox_event
WHERE (
        status IN ('NEW', 'FAILED')
        AND next_attempt_at <= #{now}
        AND (lease_until IS NULL OR lease_until <= #{now})
    )
   OR (
        status = 'PUBLISHING'
        AND lease_until <= #{now}
    )
ORDER BY id ASC
LIMIT #{limit}
FOR UPDATE SKIP LOCKED
